MERGE INTO CONSULTAS FIN USING (SELECT '002012SolicitudDeDisponibilidad' INFORME ,TO_CLOB(q'[SELECT CASE SOLICITUDDISPONIBILIDAD.TIPO_SOLICITUD WHEN 1 THEN 'SCD' WHEN 2 THEN 'ADI' WHEN 3 THEN 'RED' END TIPO, 
       SOLICITUDDISPONIBILIDAD.NUMERO,
       SOLICITUDDISPONIBILIDAD.FECHA, 
       D_SOLICITUDDISPONIBILIDAD.RUBRO,
       D_SOLICITUDDISPONIBILIDAD.FUENTE,
       D_SOLICITUDDISPONIBILIDAD.CENTRO_COSTO,
        D_SOLICITUDDISPONIBILIDAD.AUXILIAR,
       D_SOLICITUDDISPONIBILIDAD.REFERENCIA,
       SOLICITUDDISPONIBILIDAD.DEPENDENCIA,
       DEPENDENCIA.NOMBRE  NOMBRE_DEPENDENCIA,
       SOLICITUDDISPONIBILIDAD.TERCERO,
       TERCERO.NOMBRE   NOMBRE_TERCERO, 
       SOLICITUDDISPONIBILIDAD.OBJETO,
       CASE SOLICITUDDISPONIBILIDAD.APROBACION WHEN -1 THEN 'Aprobado' WHEN 0 THEN 'No Aprobado' WHEN 2 THEN 'En Revisión' WHEN  3 THEN 'Anulado' ELSE '' END AS ESTADO,
       D_SOLICITUDDISPONIBILIDAD.VALOR VALORSOLICITADO
FROM SOLICITUDDISPONIBILIDAD 
    INNER JOIN D_SOLICITUDDISPONIBILIDAD 
      ON  SOLICITUDDISPONIBILIDAD.COMPANIA = D_SOLICITUDDISPONIBILIDAD.COMPANIA
     AND  SOLICITUDDISPONIBILIDAD.NUMERO   = D_SOLICITUDDISPONIBILIDAD.NUMERO
     AND  SOLICITUDDISPONIBILIDAD.TIPO_SOLICITUD      = D_SOLICITUDDISPONIBILIDAD.TIPO_SOLICITUD
    INNER JOIN DEPENDENCIA 
      ON SOLICITUDDISPONIBILIDAD.COMPANIA    = DEPENDENCIA.COMPANIA
     AND SOLICITUDDISPONIBILIDAD.DEPENDENCIA = DEPENDENCIA.CODIGO
    INNER JOIN TERCERO 
      ON SOLICITUDDISPONIBILIDAD.COMPANIA    = TERCERO.COMPANIA
     AND SOLICITUDDISPONIBILIDAD.TERCERO     = TERCERO.NIT
     AND SOLICITUDDISPONIBILIDAD.SUCURSAL    = TERCERO.SUCURSAL
WHERE SOLICITUDDISPONIBILIDAD.COMPANIA         = s$compania$s
  AND SOLICITUDDISPONIBILIDAD.ANO              = s$anio$s
  AND D_SOLICITUDDISPONIBILIDAD.RUBRO          BETWEEN 's$rubroInicial$s' AND 's$rubroFinal$s'
  AND SOLICITUDDISPONIBILIDAD.FECHA          BETWEEN 's$fechaInicial$s' AND 's$fechaFinal$s'
  AND D_SOLICITUDDISPONIBILIDAD.AUXILIAR       BETWEEN CASE WHEN 0 NOT IN  s$manAux$s THEN 's$auxiliarInicial$s'   ELSE D_SOLICITUDDISPONIBILIDAD.AUXILIAR       END AND CASE WHEN 0 NOT IN  s$manAux$s THEN 's$auxiliarFinal$s'   ELSE D_SOLICITUDDISPONIBILIDAD.AUXILIAR       END
  AND D_SOLICITUDDISPONIBILIDAD.CENTRO_COSTO   BETWEEN CASE WHEN 0 NOT IN  s$manCen$s THEN 's$centroInicial$s'     ELSE D_SOLICITUDDISPONIBILIDAD.CENTRO_COSTO   END AND CASE WHEN 0 NOT IN  s$manCen$s THEN 's$centroFinal$s'     ELSE D_SOLICITUDDISPONIBILIDAD.CENTRO_COSTO   END
  AND D_SOLICITUDDISPONIBILIDAD.REFERENCIA     BETWEEN CASE WHEN 0 NOT IN  s$manRef$s THEN 's$referenciaInicial$s' ELSE D_SOLICITUDDISPONIBILIDAD.REFERENCIA     END AND CASE WHEN 0 NOT IN  s$manRef$s THEN 's$referenciaFinal$s' ELSE D_SOLICITUDDISPONIBILIDAD.REFERENCIA     END
  AND D_SOLICITUDDISPONIBILIDAD.FUENTE BETWEEN CASE WHEN 0 NOT IN  s$manFue$s THEN 's$fuenteInicial$s'     ELSE D_SOLICITUDDISPONIBILIDAD.FUENTE END AND CASE WHEN 0 NOT IN  s$manFue$s THEN 's$fuenteFinal$s'     ELSE D_SOLICITUDDISPONIBILIDAD.FUENTE END]') CONSULTA, 3 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);